const newDesign=document.querySelector("#lembar"),slider=document.querySelector("#slider");let scrollLeft,startX,isDown=!1;newDesign.addEventListener("mousedown",e=>{isDown=!0,newDesign.classList.add("active"),startX=e.pageX-newDesign.offsetLeft,scrollLeft=newDesign.scrollLeft}),newDesign.addEventListener("mouseleave",()=>{isDown=!1,newDesign.classList.remove("active")}),newDesign.addEventListener("mouseup",()=>{isDown=!1,newDesign.classList.remove("active")}),newDesign.addEventListener("mousemove",e=>{if(!isDown)return;e.preventDefault();const s=e.pageX-newDesign.offsetLeft,t=3*(s-startX);newDesign.scrollLeft=scrollLeft-t}),slider.addEventListener("mousedown",e=>{isDown=!0,slider.classList.add("active"),startX=e.pageX-slider.offsetLeft,scrollLeft=slider.scrollLeft}),slider.addEventListener("mouseleave",()=>{isDown=!1,slider.classList.remove("active")}),slider.addEventListener("mouseup",()=>{isDown=!1,slider.classList.remove("active")}),slider.addEventListener("mousemove",e=>{if(!isDown)return;e.preventDefault();const s=e.pageX-slider.offsetLeft,t=3*(s-startX);slider.scrollLeft=scrollLeft-t,console.log(t)});